// Desktop: click Work -> jump to #web-work
  // Desktop: hover still opens dropdown via CSS
  document.addEventListener("DOMContentLoaded", () => {
    const workLink = document.querySelector(".nav-item.dropdown > a.nav-link.dropdown-toggle");
    if (!workLink) return;

    workLink.addEventListener("click", (e) => {
      // Only force navigation on desktop
      if (window.matchMedia("(min-width: 992px)").matches) {
        e.preventDefault();
        const target = workLink.getAttribute("href"); // "#web-work"
        if (target && target.startsWith("#")) {
          document.querySelector(target)?.scrollIntoView({ behavior: "smooth" });
        } else if (target) {
          window.location.href = target;
        }
      }
      // On mobile, Bootstrap handles click-to-open dropdown normally
    });
  });

// ---

const form = document.querySelector('form[action="https://formspree.io/f/mdalybja"]');
  const statusEl = document.getElementById("form-status");

  if (form && statusEl) {
    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      statusEl.textContent = "Sending...";

      const data = new FormData(form);
      try {
        const res = await fetch(form.action, {
          method: form.method,
          body: data,
          headers: { "Accept": "application/json" }
        });

        if (res.ok) {
          statusEl.textContent = "✅ Sent! I’ll get back to you soon.";
          form.reset();
        } else {
          statusEl.textContent = "❌ Something went wrong. Try again.";
        }
      } catch {
        statusEl.textContent = "❌ Network error. Try again.";
      }
    });
  }

// ---

document.addEventListener("DOMContentLoaded", () => {
  const track = document.getElementById("testimonialsTrack");
  if (!track) return;

  const prevBtn = document.querySelector(".testi-prev");
  const nextBtn = document.querySelector(".testi-next");
  const slides = Array.from(track.querySelectorAll(".testi-slide"));

  let index = 0;

  const getSlideWidth = () => slides[0].getBoundingClientRect().width;
  const getGap = () => {
    const styles = window.getComputedStyle(track);
    return parseFloat(styles.columnGap || styles.gap || "16");
  };

  const maxIndex = () => {
    // how many are visible based on breakpoint
    const vw = window.innerWidth;
    const visible = vw <= 575 ? 1 : vw <= 991 ? 2 : 3;
    return Math.max(0, slides.length - visible);
  };

  const update = () => {
    const w = getSlideWidth();
    const gap = getGap();
    index = Math.min(Math.max(index, 0), maxIndex());
    track.style.transform = `translateX(${-index * (w + gap)}px)`;
    if (prevBtn) prevBtn.disabled = index === 0;
    if (nextBtn) nextBtn.disabled = index === maxIndex();
  };

  prevBtn?.addEventListener("click", () => { index -= 1; update(); });
  nextBtn?.addEventListener("click", () => { index += 1; update(); });
  window.addEventListener("resize", update);

  update();
});

// ---

document.addEventListener("DOMContentLoaded", () => {
  const counters = document.querySelectorAll(".counter");

  const animateCounter = (counter) => {
    const target = Number(counter.dataset.target || 0);
    const suffix = counter.dataset.suffix || "";
    const duration = 1200;
    const startTime = performance.now();

    const step = (now) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const value = Math.round(target * progress);

      counter.textContent = `${value}${suffix}`;

      if (progress < 1) requestAnimationFrame(step);
    };

    requestAnimationFrame(step);
  };

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        animateCounter(entry.target);
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.6 });

  counters.forEach((counter) => observer.observe(counter));
});

